import * as fs from 'fs';
import * as path from 'path';

export interface SpartaRecord {
  totalBattles: number;
  victories: number;
  defeats: number;
  wondersBuilt: number;
  citiesLost: number;
  currentStreak: number;
  greatGenerals: number;
  lastUpdated: string;
}

export type SpartaEvent = 'BATTLE_WON' | 'BATTLE_LOST' | 'WONDER_BUILT' | 'CITY_LOST' | 'GREAT_GENERAL';

const DEFAULT_RECORD: SpartaRecord = {
  totalBattles: 0,
  victories: 0,
  defeats: 0,
  wondersBuilt: 0,
  citiesLost: 0,
  currentStreak: 0,
  greatGenerals: 0,
  lastUpdated: new Date().toISOString(),
};

export class SpartaRecordManager {
  private record: SpartaRecord = { ...DEFAULT_RECORD };
  private filePath: string = '';

  load(stateDir: string): SpartaRecord {
    this.filePath = path.join(stateDir, 'sparta-record.json');
    if (fs.existsSync(this.filePath)) {
      try {
        this.record = JSON.parse(fs.readFileSync(this.filePath, 'utf-8'));
      } catch {
        this.record = { ...DEFAULT_RECORD };
      }
    } else {
      this.record = { ...DEFAULT_RECORD };
    }
    return this.record;
  }

  recordRunEnd(passed: number, failed: number, allFirstTry: boolean): SpartaEvent[] {
    const events: SpartaEvent[] = [];
    this.record.totalBattles++;

    if (failed === 0 && passed > 0) {
      this.record.victories++;
      this.record.currentStreak = this.record.currentStreak > 0 ? this.record.currentStreak + 1 : 1;
      events.push('BATTLE_WON');
    } else if (passed === 0) {
      this.record.defeats++;
      this.record.currentStreak = this.record.currentStreak < 0 ? this.record.currentStreak - 1 : -1;
      events.push('BATTLE_LOST');
    } else {
      this.record.currentStreak = 0;
    }

    if (this.record.currentStreak === 5) {
      this.record.wondersBuilt++;
      events.push('WONDER_BUILT');
    }
    if (this.record.currentStreak === -3) {
      this.record.citiesLost++;
      events.push('CITY_LOST');
    }
    if (allFirstTry) {
      this.record.greatGenerals++;
      events.push('GREAT_GENERAL');
    }

    this.record.lastUpdated = new Date().toISOString();
    this.save();
    return events;
  }

  save(): void {
    if (this.filePath) {
      try { fs.mkdirSync(path.dirname(this.filePath), { recursive: true }); } catch {}
      fs.writeFileSync(this.filePath, JSON.stringify(this.record, null, 2));
    }
  }

  getRecord(): SpartaRecord {
    return this.record;
  }
}

