import * as http from 'http';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import { exec } from 'child_process';
import { SpartaRecordManager } from '../core/sparta-record.js';
import { HelotEngine } from '../core/engine.js';

const DASHBOARD_HTML = path.resolve(__dirname, '../../src/dashboard/index.html');

function readFrontierEstimate(): number {
  try {
    const p = path.join(os.homedir(), '.claude', 'helots-frontier-calls.json');
    if (!fs.existsSync(p)) return 0;
    const data = JSON.parse(fs.readFileSync(p, 'utf-8'));
    return (data.toolCalls || 0) * 500;
  } catch {
    return 0;
  }
}

function serveSSE(
  res: http.ServerResponse,
  logFile: string,
  intervalMs = 200
): () => void {
  res.writeHead(200, {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    'Connection': 'keep-alive',
    'Access-Control-Allow-Origin': '*',
  });

  let offset = fs.existsSync(logFile) ? fs.statSync(logFile).size : 0;

  const ping = setInterval(() => {
    try { res.write(':ping\n\n'); } catch {}
  }, 15000);

  const poll = setInterval(() => {
    if (!fs.existsSync(logFile)) return;
    const size = fs.statSync(logFile).size;
    if (size <= offset) return;
    const buf = Buffer.alloc(size - offset);
    const fd = fs.openSync(logFile, 'r');
    fs.readSync(fd, buf, 0, buf.length, offset);
    fs.closeSync(fd);
    offset = size;
    const lines = buf.toString('utf-8').split('\n').filter(l => l.trim());
    for (const line of lines) {
      try { res.write(`data: ${line}\n\n`); } catch {}
    }
  }, intervalMs);

  return () => {
    clearInterval(ping);
    clearInterval(poll);
  };
}

export function startDashboard(
  engine: HelotEngine,
  stateDir: string,
  port = 7771
): void {
  const spartaRecord = new SpartaRecordManager();
  spartaRecord.load(stateDir);

  const server = http.createServer((req, res) => {
    const url = new URL(req.url || '/', `http://localhost:${port}`);
    const pathname = url.pathname;

    // CORS
    res.setHeader('Access-Control-Allow-Origin', '*');

    if (req.method === 'GET' && pathname === '/') {
      const htmlPath = path.resolve(path.join(path.dirname(path.dirname(stateDir)), 'src', 'dashboard', 'index.html'));
      if (fs.existsSync(htmlPath)) {
        res.writeHead(200, { 'Content-Type': 'text/html' });
        res.end(fs.readFileSync(htmlPath));
      } else {
        res.writeHead(404);
        res.end('Dashboard not found: ' + htmlPath);
      }
      return;
    }

    if (req.method === 'GET' && pathname === '/events') {
      const eventsFile = path.join(stateDir, 'events.jsonl');
      const cleanup = serveSSE(res, eventsFile);
      req.on('close', cleanup);
      return;
    }

    if (req.method === 'GET' && pathname === '/api/stream') {
      const streamFile = path.join(stateDir, 'stream.log');
      const cleanup = serveSSE(res, streamFile);
      req.on('close', cleanup);
      return;
    }

    if (req.method === 'GET' && pathname === '/api/stats') {
      const record = spartaRecord.getRecord();
      const frontierEstimate = readFrontierEstimate();

      // Read latest psiloiMetrics from events.jsonl
      let localTokens = { in: 0, out: 0, tps: 0 };
      let currentRun: any = null;
      try {
        const eventsFile = path.join(stateDir, 'events.jsonl');
        if (fs.existsSync(eventsFile)) {
          const lines = fs.readFileSync(eventsFile, 'utf-8').split('\n').filter(l => l.trim());
          for (const line of lines) {
            try {
              const ev = JSON.parse(line);
              if (ev.type === 'run_start') currentRun = ev;
              if (ev.type === 'subagent_done' && ev.psiloiMetrics) {
                const m = ev.psiloiMetrics;
                const roles = ['scout', 'builder', 'peltast', 'aristomenis', 'slinger'] as const;
                let totalIn = 0, totalOut = 0, totalTps = 0, count = 0;
                for (const r of roles) {
                  if (m[r]) {
                    totalIn += m[r].in || 0;
                    totalOut += m[r].out || 0;
                    totalTps += m[r].tps || 0;
                    count++;
                  }
                }
                localTokens = { in: totalIn, out: totalOut, tps: count > 0 ? totalTps / count : 0 };
              }
            } catch {}
          }
        }
      } catch {}

      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ localTokens, frontierEstimate, record, currentRun }));
      return;
    }

    if (req.method === 'GET' && pathname === '/api/runs') {
      try {
        const runsDir = path.join(stateDir, 'runs');
        if (!fs.existsSync(runsDir)) { res.writeHead(200, { 'Content-Type': 'application/json' }); res.end('[]'); return; }
        const runs = fs.readdirSync(runsDir)
          .map(name => {
            const dir = path.join(runsDir, name);
            const stat = fs.statSync(dir);
            const progressFile = path.join(dir, 'progress.md');
            const reviewFile = path.join(dir, 'review.md');
            return {
              id: name,
              mtime: stat.mtimeMs,
              hasProgress: fs.existsSync(progressFile),
              hasReview: fs.existsSync(reviewFile),
              progressPath: progressFile,
              reviewPath: reviewFile,
            };
          })
          .sort((a, b) => b.mtime - a.mtime);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(runs));
      } catch (e: any) {
        res.writeHead(500);
        res.end(e.message);
      }
      return;
    }

    if (req.method === 'GET' && pathname === '/api/file') {
      const filePath = url.searchParams.get('path') || '';
      if (!filePath.endsWith('.md')) {
        res.writeHead(403);
        res.end('Only .md files allowed');
        return;
      }
      if (!fs.existsSync(filePath)) {
        res.writeHead(404);
        res.end('File not found');
        return;
      }
      res.writeHead(200, { 'Content-Type': 'text/plain; charset=utf-8' });
      res.end(fs.readFileSync(filePath, 'utf-8'));
      return;
    }

    if (req.method === 'POST' && (pathname === '/api/run' || pathname === '/api/slinger' || pathname === '/api/hoplite')) {
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const payload = JSON.parse(body || '{}');
          let result: string;
          if (pathname === '/api/run') {
            result = await engine.executeHelots(payload.taskSummary || '', payload.implementationPlan || '', () => {}, payload.tasks);
          } else if (pathname === '/api/slinger') {
            result = await engine.executeSlinger(payload.researchTask || '', undefined, () => {});
          } else {
            result = await engine.executeHoplite(payload.file || '', payload.instruction || '', () => {});
          }
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ result }));
        } catch (e: any) {
          res.writeHead(500);
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    res.writeHead(404);
    res.end('Not found');
  });

  server.listen(port, () => {
    process.stderr.write(`[dashboard] Running at http://localhost:${port}\n`);
    if (process.platform === 'win32') {
      exec(`start http://localhost:${port}`);
    } else if (process.platform === 'darwin') {
      exec(`open http://localhost:${port}`);
    }
  });
}

