<script>
const state = { tasks: {}, phase: 'idle' };

// SSE — events
const evtSrc = new EventSource('/events');
evtSrc.onmessage = e => {
  try { handleEvent(JSON.parse(e.data)); } catch {}
};

// SSE — stream
const streamSrc = new EventSource('/api/stream');
streamSrc.onmessage = e => {
  const panel = document.getElementById('stream-panel');
  panel.textContent += e.data + '\n';
  panel.scrollTop = panel.scrollHeight;
};

function handleEvent(ev) {
  const panel = document.getElementById('events-panel');
  const entry = document.createElement('div');
  entry.className = 'text-xs text-gray-300 border-b border-gray-800 pb-1';
  entry.textContent = JSON.stringify(ev);
  panel.appendChild(entry);
  panel.scrollTop = panel.scrollHeight;

  if (ev.type === 'run_start') {
    state.tasks = {};
    renderTasks();
    document.getElementById('phase-name').textContent = 'starting';
    document.getElementById('stream-panel').textContent = '';
    showToast('📯', 'NEW CAMPAIGN', 'Sparta marches to war.', 'border-yellow-600');
    document.getElementById('hdr-model').textContent = ev.model || '';
    document.getElementById('hdr-project').textContent = ev.projectRoot ? ev.projectRoot.split(/[\/\\]/).pop() : '';
  }
  if (ev.type === 'task_list') {
    state.tasks = {};
    for (const t of (ev.tasks || [])) state.tasks[t.id] = { ...t, status: 'pending' };
    renderTasks();
  }
  if (ev.type === 'task_status') {
    if (state.tasks[ev.taskId]) state.tasks[ev.taskId].status = ev.status;
    renderTasks();
  }
  if (ev.type === 'phase_change') {
    document.getElementById('phase-name').textContent = ev.name || ev.phase || '';
  }
  if (ev.type === 'verdict') {
    if (state.tasks[ev.taskId]) state.tasks[ev.taskId].verdict = ev.result;
    renderTasks();
  }
  if (ev.type === 'run_end') {
    fetchStats();
    loadRuns();
    const p = ev.passed || 0, f = ev.failed || 0;
    if (f === 0 && p > 0) showToast('⚔️', 'BATTLE WON', `The phalanx holds the line! ${p} tasks, 0 failed`, 'border-green-600');
    else if (p === 0) showToast('💀', 'BATTLE LOST', 'Sparta mourns her fallen.', 'border-red-600');
    else showToast('⚔️', 'PYRRHIC VICTORY', `Victory, but at a cost. ${p} pass, ${f} fail`, 'border-orange-600');
  }
  if (ev.spartaEvent) {
    if (ev.spartaEvent === 'WONDER_BUILT') showToast('🏛️', 'WONDER BUILT', 'With your shield or on it.', 'border-yellow-500');
    if (ev.spartaEvent === 'CITY_LOST') showToast('🏚️', 'CITY LOST', 'Athens advances on Sparta.', 'border-red-800');
    if (ev.spartaEvent === 'GREAT_GENERAL') showToast('🦅', 'GREAT GENERAL', 'A general worthy of Sparta.', 'border-purple-500');
  }
}

function renderTasks() {
  const el = document.getElementById('task-list');
  el.innerHTML = '';
  for (const t of Object.values(state.tasks)) {
    const icon = t.status === 'completed' && t.verdict === 'PASS' ? '✅'
      : t.status === 'completed' && t.verdict === 'FAIL' ? '❌'
      : t.status === 'in_progress' ? '🔄' : '⏳';
    const div = document.createElement('div');
    div.className = 'flex gap-2';
    div.innerHTML = `<span>${icon}</span><span class="truncate text-gray-300">${t.desc || t.id}</span>`;
    el.appendChild(div);
  }
}

function showToast(icon, title, body, borderClass) {
  const c = document.getElementById('toast-container');
  const d = document.createElement('div');
  d.className = `toast bg-gray-900 border ${borderClass} rounded p-3 max-w-xs shadow-xl`;
  d.innerHTML = `<div class="font-bold text-sm">${icon} ${title}</div><div class="text-xs text-gray-300 mt-1">${body}</div>`;
  c.appendChild(d);
  setTimeout(() => d.remove(), 5200);
}

async function fetchStats() {
  try {
    const r = await fetch('/api/stats').then(r => r.json());
    document.getElementById('tok-in').textContent = Math.round(r.localTokens.in / 1000);
    document.getElementById('tok-out').textContent = Math.round(r.localTokens.out / 1000);
    document.getElementById('tok-frontier').textContent = Math.round(r.frontierEstimate / 1000);
    document.getElementById('tok-tps').textContent = r.localTokens.tps > 0 ? r.localTokens.tps.toFixed(1) : '-';
    const rec = r.record;
    document.getElementById('stat-v').textContent = rec.victories;
    document.getElementById('stat-d').textContent = rec.defeats;
    document.getElementById('stat-b').textContent = rec.totalBattles;
    document.getElementById('stat-w').textContent = rec.wondersBuilt;
    document.getElementById('stat-g').textContent = rec.greatGenerals;
    const s = document.getElementById('stat-s');
    s.textContent = (rec.currentStreak > 0 ? '+' : '') + rec.currentStreak;
    s.className = 'font-bold ' + (rec.currentStreak > 0 ? 'text-green-400' : rec.currentStreak < 0 ? 'text-red-400' : 'text-gray-400');
  } catch {}
}

async function loadRuns() {
  try {
    const runs = await fetch('/api/runs').then(r => r.json());
    const el = document.getElementById('runs-list');
    el.innerHTML = '';
    for (const run of runs.slice(0, 20)) {
      const d = document.createElement('div');
      d.className = 'flex gap-2 items-center cursor-pointer hover:bg-gray-800 rounded p-1';
      d.innerHTML = `<span class="text-gray-400 truncate flex-1">${run.id}</span>`;
      if (run.hasReview) {
        const btn = document.createElement('button');
        btn.className = 'text-blue-400 hover:text-blue-300 flex-shrink-0';
        btn.textContent = 'review';
        btn.onclick = () => openMd(run.reviewPath, run.id + ' — review');
        d.appendChild(btn);
      }
      if (run.hasProgress) {
        const btn = document.createElement('button');
        btn.className = 'text-green-400 hover:text-green-300 flex-shrink-0';
        btn.textContent = 'progress';
        btn.onclick = () => openMd(run.progressPath, run.id + ' — progress');
        d.appendChild(btn);
      }
      el.appendChild(d);
    }
  } catch {}
}

async function openMd(filePath, title) {
  try {
    const text = await fetch('/api/file?path=' + encodeURIComponent(filePath)).then(r => r.text());
    document.getElementById('modal-title').textContent = title;
    document.getElementById('modal-content').innerHTML = marked.parse(text);
    document.getElementById('md-modal').classList.remove('hidden');
  } catch (e) {
    alert('Could not load file: ' + e.message);
  }
}

function closeModal(e) {
  if (e.target === document.getElementById('md-modal')) document.getElementById('md-modal').classList.add('hidden');
}

async function doRun() {
  const summary = document.getElementById('run-summary').value.trim();
  const plan = document.getElementById('run-plan').value.trim();
  if (!summary) return;
  document.getElementById('action-result').textContent = 'Running...';
  const r = await fetch('/api/run', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ taskSummary: summary, implementationPlan: plan }) }).then(r => r.json());
  document.getElementById('action-result').textContent = r.result || r.error || JSON.stringify(r);
}

async function doSlinger() {
  const task = document.getElementById('slinger-task').value.trim();
  if (!task) return;
  document.getElementById('action-result').textContent = 'Researching...';
  const r = await fetch('/api/slinger', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ researchTask: task }) }).then(r => r.json());
  document.getElementById('action-result').textContent = r.result || r.error || JSON.stringify(r);
}

async function doHoplite() {
  const file = document.getElementById('hoplite-file').value.trim();
  const instr = document.getElementById('hoplite-instr').value.trim();
  if (!file || !instr) return;
  document.getElementById('action-result').textContent = 'Editing...';
  const r = await fetch('/api/hoplite', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ file, instruction: instr }) }).then(r => r.json());
  document.getElementById('action-result').textContent = r.result || r.error || JSON.stringify(r);
}

